@Entity
@Table(name = "orders")
@EntityListeners(AuditingEntityListener.class)
@Data
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class Order {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(name = "order_number", unique = true, nullable = false)
    private String orderNumber;

    @NotNull(message = "Customer is required")
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "customer_id", nullable = false)
    private Customer customer;

    @OneToMany(mappedBy = "order", cascade = CascadeType.ALL, orphanRemoval = true)
    @Builder.Default
    private List<OrderItem> items = new ArrayList<>();

    @NotNull(message = "Order status is required")
    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private OrderStatus status;

    @DecimalMin(value = "0.0", message = "Total amount must be positive")
    @Column(name = "total_amount", precision = 10, scale = 2)
    private BigDecimal totalAmount;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "shipping_address_id")
    private Address shippingAddress;

    @Column(name = "notes", length = 1000)
    private String notes;

    @CreatedDate
    @Column(name = "created_at", nullable = false, updatable = false)
    private LocalDateTime createdAt;

    @LastModifiedDate
    @Column(name = "updated_at")
    private LocalDateTime updatedAt;

    @CreatedBy
    @Column(name = "created_by", updatable = false)
    private String createdBy;

    @LastModifiedBy
    @Column(name = "updated_by")
    private String updatedBy;

    @Version
    private Long version;

    @PrePersist
    public void prePersist() {
        if (orderNumber == null) {
            orderNumber = "ORD-" + UUID.randomUUID().toString().substring(0, 8).toUpperCase();
        }
        if (status == null) {
            status = OrderStatus.PENDING;
        }
    }

    public void addItem(OrderItem item) {
        items.add(item);
        item.setOrder(this);
    }

    public void removeItem(OrderItem item) {
        items.remove(item);
        item.setOrder(null);
    }

    public void calculateTotal() {
        this.totalAmount = items.stream()
                .map(item -> item.getPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }
}

@Service
@EnableScheduling
public class ScheduledTaskService {

    private static final Logger logger = LoggerFactory.getLogger(ScheduledTaskService.class);

    private final OrderRepository orderRepository;
    private final NotificationService notificationService;
    private final ReportService reportService;

    @Autowired
    public ScheduledTaskService(OrderRepository orderRepository,
                                 NotificationService notificationService,
                                 ReportService reportService) {
        this.orderRepository = orderRepository;
        this.notificationService = notificationService;
        this.reportService = reportService;
    }

    @Scheduled(fixedRate = 300000) // Every 5 minutes
    public void processAbandonedCarts() {
        logger.info("Starting abandoned cart processing");
        LocalDateTime threshold = LocalDateTime.now().minusHours(24);
        List<Order> abandonedOrders = orderRepository
                .findByStatusAndCreatedAtBefore(OrderStatus.PENDING, threshold);

        abandonedOrders.forEach(order -> {
            try {
                notificationService.sendAbandonedCartReminder(order);
                logger.info("Sent reminder for order: {}", order.getId());
            } catch (Exception e) {
                logger.error("Failed to process abandoned order: {}", order.getId(), e);
            }
        });
        logger.info("Completed abandoned cart processing. Processed {} orders", abandonedOrders.size());
    }

    @Scheduled(cron = "0 0 2 * * ?") // Daily at 2 AM
    public void generateDailyReport() {
        logger.info("Starting daily report generation");
        try {
            LocalDate yesterday = LocalDate.now().minusDays(1);
            reportService.generateDailySalesReport(yesterday);
            logger.info("Daily report generated successfully for {}", yesterday);
        } catch (Exception e) {
            logger.error("Failed to generate daily report", e);
        }
    }

    @Scheduled(cron = "0 0 0 1 * ?") // First day of each month at midnight
    public void generateMonthlyReport() {
        logger.info("Starting monthly report generation");
        YearMonth lastMonth = YearMonth.now().minusMonths(1);
        reportService.generateMonthlySalesReport(lastMonth);
    }

    @Scheduled(fixedDelay = 60000, initialDelay = 10000) // Every minute after 10s initial delay
    @Async
    public void cleanupExpiredTokens() {
        logger.debug("Cleaning up expired tokens");
        int deleted = tokenRepository.deleteExpiredTokens(LocalDateTime.now());
        if (deleted > 0) {
            logger.info("Deleted {} expired tokens", deleted);
        }
    }

    @Scheduled(cron = "0 */15 * * * ?") // Every 15 minutes
    public void healthCheck() {
        logger.debug("Performing system health check");
        // Perform health checks on external services
    }
}

@SpringBootTest
@AutoConfigureMockMvc
@Transactional
class UserControllerIntegrationTest {

    @Autowired
    private MockMvc mockMvc;

    @Autowired
    private ObjectMapper objectMapper;

    @Autowired
    private UserRepository userRepository;

    private User testUser;

    @BeforeEach
    void setUp() {
        testUser = User.builder()
                .email("test@example.com")
                .firstName("John")
                .lastName("Doe")
                .password("password123")
                .active(true)
                .build();
        testUser = userRepository.save(testUser);
    }

    @Test
    @DisplayName("GET /api/users - should return all users")
    void getAllUsers_ReturnsUserList() throws Exception {
        mockMvc.perform(get("/api/users")
                        .contentType(MediaType.APPLICATION_JSON))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.APPLICATION_JSON))
                .andExpect(jsonPath("$", hasSize(greaterThanOrEqualTo(1))))
                .andExpect(jsonPath("$[0].email").value("test@example.com"));
    }

    @Test
    @DisplayName("GET /api/users/{id} - should return user when exists")
    void getUserById_WhenExists_ReturnsUser() throws Exception {
        mockMvc.perform(get("/api/users/{id}", testUser.getId())
                        .contentType(MediaType.APPLICATION_JSON))
                .andExpect(status().isOk())
                .andExpect(jsonPath("$.id").value(testUser.getId()))
                .andExpect(jsonPath("$.email").value("test@example.com"))
                .andExpect(jsonPath("$.firstName").value("John"));
    }

    @Test
    @DisplayName("GET /api/users/{id} - should return 404 when not exists")
    void getUserById_WhenNotExists_Returns404() throws Exception {
        mockMvc.perform(get("/api/users/{id}", 99999L)
                        .contentType(MediaType.APPLICATION_JSON))
                .andExpect(status().isNotFound());
    }

    @Test
    @DisplayName("POST /api/users - should create new user")
    void createUser_WithValidData_ReturnsCreatedUser() throws Exception {
        UserRequest request = new UserRequest("new@example.com", "Jane", "Smith", "password456");

        mockMvc.perform(post("/api/users")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isCreated())
                .andExpect(jsonPath("$.email").value("new@example.com"))
                .andExpect(jsonPath("$.firstName").value("Jane"))
                .andExpect(jsonPath("$.id").isNotEmpty());
    }

    @Test
    @DisplayName("POST /api/users - should return 400 for invalid data")
    void createUser_WithInvalidData_Returns400() throws Exception {
        UserRequest request = new UserRequest("", "", "", "");

        mockMvc.perform(post("/api/users")
                        .contentType(MediaType.APPLICATION_JSON)
                        .content(objectMapper.writeValueAsString(request)))
                .andExpect(status().isBadRequest())
                .andExpect(jsonPath("$.fieldErrors").isNotEmpty());
    }

    @Test
    @DisplayName("DELETE /api/users/{id} - should delete existing user")
    void deleteUser_WhenExists_Returns204() throws Exception {
        mockMvc.perform(delete("/api/users/{id}", testUser.getId()))
                .andExpect(status().isNoContent());

        assertThat(userRepository.findById(testUser.getId())).isEmpty();
    }
}

@Service
@EnableAsync
public class AsyncProcessingService {

    private static final Logger logger = LoggerFactory.getLogger(AsyncProcessingService.class);

    private final ExternalApiClient apiClient;
    private final DataRepository dataRepository;

    @Autowired
    public AsyncProcessingService(ExternalApiClient apiClient, DataRepository dataRepository) {
        this.apiClient = apiClient;
        this.dataRepository = dataRepository;
    }

    @Async("taskExecutor")
    public CompletableFuture<UserData> fetchUserDataAsync(Long userId) {
        logger.info("Fetching user data for userId: {} on thread: {}", userId, Thread.currentThread().getName());
        UserData userData = apiClient.getUserData(userId);
        return CompletableFuture.completedFuture(userData);
    }

    @Async("taskExecutor")
    public CompletableFuture<List<Order>> fetchUserOrdersAsync(Long userId) {
        logger.info("Fetching orders for userId: {} on thread: {}", userId, Thread.currentThread().getName());
        List<Order> orders = dataRepository.findOrdersByUserId(userId);
        return CompletableFuture.completedFuture(orders);
    }

    @Async("taskExecutor")
    public CompletableFuture<AccountBalance> fetchAccountBalanceAsync(Long userId) {
        logger.info("Fetching balance for userId: {} on thread: {}", userId, Thread.currentThread().getName());
        AccountBalance balance = apiClient.getAccountBalance(userId);
        return CompletableFuture.completedFuture(balance);
    }

    public UserProfile getUserProfileParallel(Long userId) {
        long startTime = System.currentTimeMillis();

        CompletableFuture<UserData> userDataFuture = fetchUserDataAsync(userId);
        CompletableFuture<List<Order>> ordersFuture = fetchUserOrdersAsync(userId);
        CompletableFuture<AccountBalance> balanceFuture = fetchAccountBalanceAsync(userId);

        // Wait for all futures to complete
        CompletableFuture.allOf(userDataFuture, ordersFuture, balanceFuture).join();

        try {
            UserProfile profile = UserProfile.builder()
                    .userData(userDataFuture.get())
                    .orders(ordersFuture.get())
                    .accountBalance(balanceFuture.get())
                    .build();

            logger.info("Parallel fetch completed in {} ms", System.currentTimeMillis() - startTime);
            return profile;
        } catch (InterruptedException | ExecutionException e) {
            logger.error("Error during parallel processing", e);
            throw new ServiceException("Failed to fetch user profile", e);
        }
    }

    public List<ProcessingResult> processItemsInParallel(List<Item> items) {
        List<CompletableFuture<ProcessingResult>> futures = items.stream()
                .map(this::processItemAsync)
                .collect(Collectors.toList());

        return futures.stream()
                .map(CompletableFuture::join)
                .collect(Collectors.toList());
    }

    @Async("taskExecutor")
    public CompletableFuture<ProcessingResult> processItemAsync(Item item) {
        return CompletableFuture.supplyAsync(() -> {
            // Process item
            return new ProcessingResult(item.getId(), "SUCCESS");
        }).exceptionally(ex -> {
            logger.error("Failed to process item: {}", item.getId(), ex);
            return new ProcessingResult(item.getId(), "FAILED");
        });
    }
}

@Configuration
@EnableAsync
public class AsyncConfig {

    @Bean(name = "taskExecutor")
    public Executor taskExecutor() {
        ThreadPoolTaskExecutor executor = new ThreadPoolTaskExecutor();
        executor.setCorePoolSize(4);
        executor.setMaxPoolSize(10);
        executor.setQueueCapacity(100);
        executor.setThreadNamePrefix("AsyncTask-");
        executor.setRejectedExecutionHandler(new ThreadPoolExecutor.CallerRunsPolicy());
        executor.initialize();
        return executor;
    }
}

@Configuration
@EnableCaching
public class RedisCacheConfig {

    @Value("${spring.redis.host}")
    private String redisHost;

    @Value("${spring.redis.port}")
    private int redisPort;

    @Value("${spring.redis.password:}")
    private String redisPassword;

    @Bean
    public RedisConnectionFactory redisConnectionFactory() {
        RedisStandaloneConfiguration config = new RedisStandaloneConfiguration();
        config.setHostName(redisHost);
        config.setPort(redisPort);
        if (!redisPassword.isEmpty()) {
            config.setPassword(RedisPassword.of(redisPassword));
        }

        LettuceClientConfiguration clientConfig = LettuceClientConfiguration.builder()
                .commandTimeout(Duration.ofSeconds(5))
                .build();

        return new LettuceConnectionFactory(config, clientConfig);
    }

    @Bean
    public RedisTemplate<String, Object> redisTemplate(RedisConnectionFactory connectionFactory) {
        RedisTemplate<String, Object> template = new RedisTemplate<>();
        template.setConnectionFactory(connectionFactory);

        ObjectMapper objectMapper = new ObjectMapper();
        objectMapper.registerModule(new JavaTimeModule());
        objectMapper.activateDefaultTyping(objectMapper.getPolymorphicTypeValidator(),
                ObjectMapper.DefaultTyping.NON_FINAL);

        GenericJackson2JsonRedisSerializer serializer = new GenericJackson2JsonRedisSerializer(objectMapper);

        template.setKeySerializer(new StringRedisSerializer());
        template.setValueSerializer(serializer);
        template.setHashKeySerializer(new StringRedisSerializer());
        template.setHashValueSerializer(serializer);
        template.afterPropertiesSet();

        return template;
    }

    @Bean
    public CacheManager cacheManager(RedisConnectionFactory connectionFactory) {
        RedisCacheConfiguration defaultConfig = RedisCacheConfiguration.defaultCacheConfig()
                .entryTtl(Duration.ofMinutes(30))
                .serializeKeysWith(RedisSerializationContext.SerializationPair
                        .fromSerializer(new StringRedisSerializer()))
                .serializeValuesWith(RedisSerializationContext.SerializationPair
                        .fromSerializer(new GenericJackson2JsonRedisSerializer()))
                .disableCachingNullValues();

        Map<String, RedisCacheConfiguration> cacheConfigurations = new HashMap<>();
        cacheConfigurations.put("users", defaultConfig.entryTtl(Duration.ofHours(1)));
        cacheConfigurations.put("products", defaultConfig.entryTtl(Duration.ofMinutes(15)));
        cacheConfigurations.put("sessions", defaultConfig.entryTtl(Duration.ofHours(24)));

        return RedisCacheManager.builder(connectionFactory)
                .cacheDefaults(defaultConfig)
                .withInitialCacheConfigurations(cacheConfigurations)
                .transactionAware()
                .build();
    }
}

