// Event Publisher Service
@Service
public class OrderService {

    private static final Logger logger = LoggerFactory.getLogger(OrderService.class);

    private final OrderRepository orderRepository;
    private final ApplicationEventPublisher eventPublisher;

    @Autowired
    public OrderService(OrderRepository orderRepository, ApplicationEventPublisher eventPublisher) {
        this.orderRepository = orderRepository;
        this.eventPublisher = eventPublisher;
    }

    @Transactional
    public Order createOrder(OrderRequest request) {
        Order order = new Order();
        order.setCustomerId(request.getCustomerId());
        order.setStatus(OrderStatus.PENDING);
        order.setTotalAmount(calculateTotal(request.getItems()));

        Order savedOrder = orderRepository.save(order);

        // Publish event after transaction commits
        eventPublisher.publishEvent(new OrderCreatedEvent(this, savedOrder));

        logger.info("Order created and event published: {}", savedOrder.getId());
        return savedOrder;
    }

    private BigDecimal calculateTotal(List<OrderItemRequest> items) {
        return items.stream()
                .map(item -> item.getPrice().multiply(BigDecimal.valueOf(item.getQuantity())))
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }
}

// Event Listeners
@Component
public class OrderEventListener {

    private static final Logger logger = LoggerFactory.getLogger(OrderEventListener.class);

    private final NotificationService notificationService;
    private final InventoryService inventoryService;
    private final AnalyticsService analyticsService;

    @Autowired
    public OrderEventListener(NotificationService notificationService,
                               InventoryService inventoryService,
                               AnalyticsService analyticsService) {
        this.notificationService = notificationService;
        this.inventoryService = inventoryService;
        this.analyticsService = analyticsService;
    }

    @EventListener
    public void handleOrderCreated(OrderCreatedEvent event) {
        Order order = event.getOrder();
        logger.info("Handling OrderCreatedEvent for order: {}", order.getId());

        // Send confirmation email
        notificationService.sendOrderConfirmation(order);
    }

    @EventListener
    @Async("eventTaskExecutor")
    public void handleOrderCreatedAsync(OrderCreatedEvent event) {
        Order order = event.getOrder();
        logger.info("Async handling OrderCreatedEvent on thread: {}", Thread.currentThread().getName());

        // Reserve inventory
        inventoryService.reserveInventory(order);
    }

    @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT)
    public void handleOrderCreatedAfterCommit(OrderCreatedEvent event) {
        Order order = event.getOrder();
        logger.info("Order committed to database: {}", order.getId());

        // Track analytics after successful commit
        analyticsService.trackOrderCreated(order);
    }

    @EventListener(condition = "#event.order.totalAmount.compareTo(new java.math.BigDecimal('1000')) > 0")
    public void handleHighValueOrder(OrderCreatedEvent event) {
        Order order = event.getOrder();
        logger.info("High-value order detected: {} - ${}", order.getId(), order.getTotalAmount());

        // Alert sales team for high-value orders
        notificationService.alertSalesTeam(order);
    }

    @EventListener
    @Order(1) // Execute first
    public void handlePaymentCompleted(PaymentCompletedEvent event) {
        logger.info("Payment completed for order: {}, transaction: {}",
                event.getOrderId(), event.getTransactionId());
    }
}

