@Component
public class DatabaseHealthIndicator implements HealthIndicator {

    private final DataSource dataSource;

    @Autowired
    public DatabaseHealthIndicator(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    @Override
    public Health health() {
        try (Connection connection = dataSource.getConnection()) {
            if (connection.isValid(5)) {
                return Health.up()
                        .withDetail("database", "PostgreSQL")
                        .withDetail("status", "Connected")
                        .withDetail("url", connection.getMetaData().getURL())
                        .build();
            }
        } catch (SQLException e) {
            return Health.down()
                    .withDetail("error", e.getMessage())
                    .withException(e)
                    .build();
        }
        return Health.down().withDetail("status", "Connection invalid").build();
    }
}

@Component
public class ExternalServiceHealthIndicator implements HealthIndicator {

    private final RestTemplate restTemplate;

    @Value("${external.service.health-url}")
    private String healthUrl;

    @Autowired
    public ExternalServiceHealthIndicator(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    @Override
    public Health health() {
        try {
            ResponseEntity<String> response = restTemplate.getForEntity(healthUrl, String.class);
            if (response.getStatusCode().is2xxSuccessful()) {
                return Health.up()
                        .withDetail("service", "Payment Gateway")
                        .withDetail("responseTime", "< 1s")
                        .build();
            }
            return Health.down()
                    .withDetail("statusCode", response.getStatusCode())
                    .build();
        } catch (Exception e) {
            return Health.down()
                    .withDetail("error", "Service unreachable")
                    .withException(e)
                    .build();
        }
    }
}

@Component
public class DiskSpaceHealthIndicator implements HealthIndicator {

    @Value("${health.diskspace.threshold:10485760}") // 10MB default
    private long threshold;

    @Override
    public Health health() {
        File path = new File(".");
        long freeSpace = path.getFreeSpace();
        long totalSpace = path.getTotalSpace();
        long usedSpace = totalSpace - freeSpace;
        double usedPercentage = (double) usedSpace / totalSpace * 100;

        Health.Builder builder = freeSpace >= threshold ? Health.up() : Health.down();

        return builder
                .withDetail("total", formatBytes(totalSpace))
                .withDetail("free", formatBytes(freeSpace))
                .withDetail("used", formatBytes(usedSpace))
                .withDetail("usedPercentage", String.format("%.2f%%", usedPercentage))
                .withDetail("threshold", formatBytes(threshold))
                .build();
    }

    private String formatBytes(long bytes) {
        if (bytes < 1024) return bytes + " B";
        if (bytes < 1024 * 1024) return (bytes / 1024) + " KB";
        if (bytes < 1024 * 1024 * 1024) return (bytes / (1024 * 1024)) + " MB";
        return (bytes / (1024 * 1024 * 1024)) + " GB";
    }
}

// Custom Actuator Endpoint
@Component
@Endpoint(id = "app-info")
public class AppInfoEndpoint {

    @Value("${spring.application.name}")
    private String appName;

    @Value("${app.version:1.0.0}")
    private String appVersion;

    private final Environment environment;
    private final AtomicLong requestCount = new AtomicLong(0);
    private final LocalDateTime startTime = LocalDateTime.now();

    @Autowired
    public AppInfoEndpoint(Environment environment) {
        this.environment = environment;
    }

    @ReadOperation
    public Map<String, Object> info() {
        Map<String, Object> info = new LinkedHashMap<>();
        info.put("application", appName);
        info.put("version", appVersion);
        info.put("activeProfiles", environment.getActiveProfiles());
        info.put("startTime", startTime);
        info.put("uptime", Duration.between(startTime, LocalDateTime.now()).toString());
        info.put("totalRequests", requestCount.get());
        info.put("javaVersion", System.getProperty("java.version"));
        info.put("availableProcessors", Runtime.getRuntime().availableProcessors());

        Runtime runtime = Runtime.getRuntime();
        Map<String, Object> memory = new LinkedHashMap<>();
        memory.put("max", formatBytes(runtime.maxMemory()));
        memory.put("total", formatBytes(runtime.totalMemory()));
        memory.put("free", formatBytes(runtime.freeMemory()));
        memory.put("used", formatBytes(runtime.totalMemory() - runtime.freeMemory()));
        info.put("memory", memory);

        return info;
    }

    @ReadOperation
    public Map<String, Object> infoByComponent(@Selector String component) {
        return switch (component) {
            case "memory" -> getMemoryInfo();
            case "system" -> getSystemInfo();
            case "stats" -> getStats();
            default -> Map.of("error", "Unknown component: " + component);
        };
    }

    @WriteOperation
    public Map<String, Object> resetStats() {
        requestCount.set(0);
        return Map.of("message", "Stats reset successfully", "timestamp", LocalDateTime.now());
    }

    public void incrementRequestCount() {
        requestCount.incrementAndGet();
    }

    private Map<String, Object> getMemoryInfo() {
        Runtime runtime = Runtime.getRuntime();
        return Map.of(
                "max", runtime.maxMemory(),
                "total", runtime.totalMemory(),
                "free", runtime.freeMemory(),
                "used", runtime.totalMemory() - runtime.freeMemory()
        );
    }

    private Map<String, Object> getSystemInfo() {
        return Map.of(
                "os", System.getProperty("os.name"),
                "arch", System.getProperty("os.arch"),
                "processors", Runtime.getRuntime().availableProcessors(),
                "javaVendor", System.getProperty("java.vendor")
        );
    }

    private Map<String, Object> getStats() {
        return Map.of(
                "totalRequests", requestCount.get(),
                "uptime", Duration.between(startTime, LocalDateTime.now()).toSeconds() + " seconds"
        );
    }

    private String formatBytes(long bytes) {
        return (bytes / (1024 * 1024)) + " MB";
    }
}

@Configuration
@EnableRetry
public class RetryConfig {

    @Bean
    public RetryTemplate retryTemplate() {
        RetryTemplate retryTemplate = new RetryTemplate();

        // Exponential backoff: 1s, 2s, 4s, 8s...
        ExponentialBackOffPolicy backOffPolicy = new ExponentialBackOffPolicy();
        backOffPolicy.setInitialInterval(1000);
        backOffPolicy.setMultiplier(2.0);
        backOffPolicy.setMaxInterval(30000);
        retryTemplate.setBackOffPolicy(backOffPolicy);

        // Retry policy: max 5 attempts for specific exceptions
        Map<Class<? extends Throwable>, Boolean> retryableExceptions = new HashMap<>();
        retryableExceptions.put(TransientDataAccessException.class, true);
        retryableExceptions.put(ServiceUnavailableException.class, true);
        retryableExceptions.put(ConnectException.class, true);
        retryableExceptions.put(SocketTimeoutException.class, true);

        SimpleRetryPolicy retryPolicy = new SimpleRetryPolicy(5, retryableExceptions);
        retryTemplate.setRetryPolicy(retryPolicy);

        // Add logging listener
        retryTemplate.registerListener(new RetryListenerSupport() {
            @Override
            public <T, E extends Throwable> void onError(RetryContext context,
                                                          RetryCallback<T, E> callback,
                                                          Throwable throwable) {
                LoggerFactory.getLogger(RetryConfig.class)
                        .warn("Retry attempt {} failed: {}",
                                context.getRetryCount(),
                                throwable.getMessage());
            }
        });

        return retryTemplate;
    }
}

@Service
public class ExternalApiService {

    private static final Logger logger = LoggerFactory.getLogger(ExternalApiService.class);

    private final RestTemplate restTemplate;
    private final RetryTemplate retryTemplate;

    @Autowired
    public ExternalApiService(RestTemplate restTemplate, RetryTemplate retryTemplate) {
        this.restTemplate = restTemplate;
        this.retryTemplate = retryTemplate;
    }

    // Using @Retryable annotation
    @Retryable(
            retryFor = {ServiceUnavailableException.class, RestClientException.class},
            maxAttempts = 4,
            backoff = @Backoff(delay = 1000, multiplier = 2, maxDelay = 10000)
    )
    public PaymentResponse processPayment(PaymentRequest request) {
        logger.info("Processing payment for amount: {}", request.getAmount());

        try {
            ResponseEntity<PaymentResponse> response = restTemplate.postForEntity(
                    "https://payment-gateway.com/api/process",
                    request,
                    PaymentResponse.class
            );
            return response.getBody();
        } catch (HttpServerErrorException e) {
            logger.error("Payment gateway error: {}", e.getStatusCode());
            throw new ServiceUnavailableException("Payment gateway unavailable");
        }
    }

    @Recover
    public PaymentResponse recoverFromPaymentFailure(ServiceUnavailableException e, PaymentRequest request) {
        logger.error("All retry attempts exhausted for payment: {}", request.getOrderId());
        // Return fallback response or throw custom exception
        return PaymentResponse.builder()
                .status("FAILED")
                .message("Payment processing temporarily unavailable. Please try again later.")
                .orderId(request.getOrderId())
                .build();
    }

    // Using RetryTemplate programmatically
    public UserData fetchUserData(Long userId) {
        return retryTemplate.execute(context -> {
            logger.info("Fetching user data, attempt: {}", context.getRetryCount() + 1);
            return restTemplate.getForObject(
                    "https://user-service.com/api/users/{id}",
                    UserData.class,
                    userId
            );
        }, context -> {
            // Recovery callback
            logger.warn("All retries exhausted for user: {}, returning cached data", userId);
            return getCachedUserData(userId);
        });
    }

    // Custom retry with circuit breaker pattern
    public <T> T executeWithRetry(Supplier<T> operation, String operationName) {
        return retryTemplate.execute(
                context -> {
                    if (context.getRetryCount() > 0) {
                        logger.info("Retrying {} - attempt {}", operationName, context.getRetryCount() + 1);
                    }
                    return operation.get();
                },
                context -> {
                    logger.error("Operation {} failed after {} attempts",
                            operationName, context.getRetryCount());
                    throw new ServiceException("Operation failed: " + operationName);
                }
        );
    }

    private UserData getCachedUserData(Long userId) {
        // Return cached or default data
        return UserData.builder()
                .id(userId)
                .status("CACHED")
                .build();
    }
}

// Retryable database operations
@Service
public class OrderRepository {

    private final JdbcTemplate jdbcTemplate;

    @Retryable(
            retryFor = {TransientDataAccessException.class, DeadlockLoserDataAccessException.class},
            maxAttempts = 3,
            backoff = @Backoff(delay = 500, multiplier = 1.5)
    )
    @Transactional
    public void saveOrderWithRetry(Order order) {
        jdbcTemplate.update(
                "INSERT INTO orders (id, customer_id, total, status) VALUES (?, ?, ?, ?)",
                order.getId(),
                order.getCustomerId(),
                order.getTotal(),
                order.getStatus().name()
        );
    }

    @Recover
    public void recoverFromSaveFailure(TransientDataAccessException e, Order order) {
        // Log to dead letter queue or notify operations team
        LoggerFactory.getLogger(OrderRepository.class)
                .error("Failed to save order {} after retries", order.getId(), e);
        throw new OrderPersistenceException("Unable to save order", e);
    }
}
